import json
from pathlib import Path

DATA=Path('data')

def load(name): return json.loads((DATA/name).read_text(encoding='utf-8'))
def save(name,obj): (DATA/name).write_text(json.dumps(obj,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')
def q(i,l,s,p,o,a,e,passage=None):
    x={'id':i,'level':l,'skill':s,'prompt':p,'options':o,'answer':a,'explanation':e}
    if passage is not None:x['passage']=passage
    return x

def rotate(item,target):
    opts=item.get('options'); ans=item.get('answer')
    if not isinstance(opts,list) or len(opts)!=4 or not isinstance(ans,int): return
    correct=opts[ans]; wrong=[x for n,x in enumerate(opts) if n!=ans]; out=[]
    for n in range(4): out.append(correct if n==target else wrong.pop(0))
    item['options']=out; item['answer']=target

